constexpr double kNaN = std::numeric_limits<double>::quiet_NaN();

bool is_constraint_op(parse::Op op) noexcept {
  return op == parse::Op::EqConstraint || op == parse::Op::LtConstraint ||
         op == parse::Op::GtConstraint || op == parse::Op::DefineParam;
}

// A lavaan-shaped auto-equality row: synthesized from a shared user label,
// stamped `user = 2`, referencing two `.pN.` plabels. `from_lavaan_partable`
// drops these (the equality lives in `eq_groups` / the labels); `to_lavaan_partable`
// re-synthesizes them.
bool is_auto_equality_row(const LavaanParTable& pt, std::size_t i) noexcept {
  return pt.user[i] == 2 && pt.op[i] == parse::Op::EqConstraint;
}

